}

// escapeHTML escapes HTML special characters to prevent XSS attacks
func escapeHTML(s string) string {
	escapeMap := map[rune]string{
		'<': "&lt;",
		'>': "&gt;",
		'&': "&amp;",
		'"': "&quot;",
		'\'': "&#39;",
	}

	result := ""
	for _, ch := range s {
		if replacement, ok := escapeMap[ch]; ok {
			result += replacement
		} else {
			result += string(ch)
		}
	}
	return result
}

