// SendFeedbackEmail sends the feedback email using SMTP
func SendFeedbackEmail(auth smtp.Auth, host string, fromAddr string, toAddr string, emailBody string) error {
	// Validate required parameters
	if auth == nil {
		return fmt.Errorf("SMTP authentication is required")
	}
	if host == "" {
		return fmt.Errorf("SMTP host is required")
	}
	if fromAddr == "" {
		return fmt.Errorf("from address is required")
	}
	if toAddr == "" {
		return fmt.Errorf("to address is required")
	}
	if emailBody == "" {
		return fmt.Errorf("email body is required")
	}

	// Validate email addresses format
	if !strings.Contains(fromAddr, "@") {
		return fmt.Errorf("invalid from address format")
	}
	if !strings.Contains(toAddr, "@") {
		return fmt.Errorf("invalid to address format")
	}

	// Set up email headers
	headers := make(map[string]string)
	headers["From"] = fmt.Sprintf("User Feedback System <%s>", fromAddr)
	headers["To"] = toAddr
	headers["Subject"] = "New User Feedback Received"
	headers["MIME-Version"] = "1.0"
	headers["Content-Type"] = "text/html; charset=UTF-8"

	// Build message
	message := ""
	for k, v := range headers {
		message += fmt.Sprintf("%s: %s\r\n", k, v)
	}
	message += "\r\n" + emailBody

	// Send email with timeout
	err := smtp.SendMail(host+":587", auth, fromAddr, []string{toAddr}, []byte(message))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

