package main

import (
	"fmt"
	"html"
	"strings"
)

// BuildFeedbackEmail constructs an HTML email body from user feedback information.
// It safely escapes user inputs and formats the feedback content with line breaks.
// Parameters:
//   fromAddr: The sender's email address (not used in body, included for completeness)
//   toAddr: The recipient's email address (not used in body, included for completeness)
//   userName: The username of the feedback submitter
//   subject: The feedback subject
//   feedbackContent: The main feedback content
// Returns:
//   emailBody: HTML-formatted email body string
//   err: Always returns nil (no error expected)
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Escape special HTML characters in user inputs to prevent injection
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedback := html.EscapeString(feedbackContent)

	// Normalize newlines to \n and convert to <br> for HTML rendering
	normalized := escapedFeedback
	normalized = strings.ReplaceAll(normalized, "\r\n", "\n")
	normalized = strings.ReplaceAll(normalized, "\r", "\n")
	formattedFeedback := strings.ReplaceAll(normalized, "\n", "<br>")

	// Construct HTML email body with user feedback
	emailBody = fmt.Sprintf(`
<html>
<head>
    <title>User Feedback</title>
</head>
<body>
    <h1>User Feedback</h1>
    <p><strong>Username:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <p><strong>Feedback:</strong></p>
    <div>%s</div>
</body>
</html>`, escapedUserName, escapedSubject, formattedFeedback)

	return emailBody, nil
}

func main() {
	// Example usage of BuildFeedbackEmail
	from := "user@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with login"
	feedbackContent := "I tried to login but got an error.\nHere is the screenshot:\n[image]"

	body, err := BuildFeedbackEmail(from, to, userName, subject, feedbackContent)
	if err != nil {
		fmt.Println("Error building email:", err)
		return
	}
	fmt.Println(body)
}

